      "args": [],
      "kwargs": {},
      "notes": "Checks that only console logging is used in production."
    },
    {
      "name": "test_no_file_logging_production",
      "input": {
        "environment": "production",
        "logLevel": "info",
        "message": "Should not create file log"
      },
      "output": "No file log created",
      "args": [],
      "kwargs": {},
      "notes": "Validates that no file logging occurs in production."
    },
    {
      "name": "test_file_logging_override_production",
      "input": {
        "environment": "production",
        "logLevel": "info",
        "message": "Production log with file override",
        "enableFileLogging": true
      },
      "output": "File log created with message: Production log with file override",
      "args": [],
      "kwargs": {},
      "notes": "Tests file logging in production when overridden."
    },
    {
      "name": "test_error_handling_invalid_log_level",
      "input": {
        "environment": "production",
