      "args": [],
      "kwargs": {},
      "notes": "Checks error handling for invalid log levels."
    },
    {
      "name": "test_startup_without_logs_directory",
      "input": {
        "environment": "production"
      },
      "output": "Application started successfully",
      "args": [],
      "kwargs": {},
      "notes": "Ensures application can start without attempting to create logs directory."
    },
    {
      "name": "test_logging_formatting",
      "input": {
        "environment": "development",
        "logLevel": "info",
        "message": "Formatted log message"
      },
      "output": "Formatted log: [INFO] Formatted log message",
